/**
 * 런타임 설정 모듈.
 * @type {object}
 */
const config = require("config");

/**
 * Jsoup API 진입점.
 * @type {object}
 */
const Jsoup = org.jsoup.Jsoup;

/**
 * Jsoup HTTP Method enum.
 * @type {object}
 */
const ConnectionMethod = org.jsoup.Connection.Method;

/**
 * API utility module.
 * This file is intentionally limited to API/crawler request helpers.
 */

/**
 * Convert string HTTP method names into the MessengerBot runtime's Jsoup enum.
 * Unknown values fall back to GET to keep request behavior predictable.
 * @param {string} method
 * @returns {object}
 */
const resolveConnectionMethod = (method) => {
	// 문자열 메서드를 런타임 enum으로 안전하게 변환한다.
	switch(method){
		case "POST":
			return ConnectionMethod.POST;
		case "PUT":
			return ConnectionMethod.PUT;
		case "PATCH":
			return ConnectionMethod.PATCH;
		case "DELETE":
			return ConnectionMethod.DELETE;
		default:
			return ConnectionMethod.GET;
	}
};

/**
 * Shared JSON request helper for all crawler/API calls.
 * Centralizes timeout, headers, JSON body encoding, and JSON parsing.
 * @param {string} url
 * @param {string} method
 * @param {object} body
 * @returns {object|null}
 */
const requestJson = (url, method, body) => {
	// 공통 헤더/타임아웃을 적용한 커넥션을 준비한다.
	let connection = Jsoup.connect(url).ignoreContentType(true).header("Accept", "application/json").timeout(10000);
	
	// GET 요청은 get() 경로로 처리한다.
	if(!method || method === "GET"){
		const getResponseText = connection.get().body().text();
		return getResponseText ? JSON.parse(getResponseText) : null;
	}
	
	// GET 외 요청은 method를 명시한다.
	connection = connection.method(resolveConnectionMethod(method));
	
	// body가 있으면 JSON으로 인코딩해 요청 본문에 넣는다.
	if(body){
		connection = connection.header("Content-Type", "application/json; charset=UTF-8").requestBody(JSON.stringify(body));
	}
	
	// execute 결과를 JSON으로 파싱하고, 빈 응답은 null을 반환한다.
	const executeResponseText = connection.execute().body();
	return executeResponseText ? JSON.parse(executeResponseText) : null;
};

/**
 * 읽기 전용 JSON endpoint 호출 헬퍼.
 * @param {string} url
 * @returns {object|null}
 */
const getResponse = (url) => {
	// 읽기 전용 호출은 GET 헬퍼를 재사용한다.
	return requestJson(url, "GET");
};

/**
 * 상대 경로를 API base URL 기준 절대 경로로 변환한다.
 * @param {string} url
 * @returns {string}
 */
function getMobinogiUrl(url){
	// 입력이 없으면 빈 문자열을 반환한다.
	if(!url){
		return "";
	}
	// 상대 경로를 API_BASE_URL 기준 절대 경로로 변환한다.
	return `${config.API_BASE_URL}/${url}`;
}

/**
 * Item lookup crawler flow.
 * 1) Search by keyword.
 * 2) Use the first matched item name.
 * 3) Fetch the detailed item payload by exact name.
 * @param {string} itemName
 * @returns {object|null}
 */
function getMobinogiItem(itemName){
	// 운영 로그 추적을 위해 검색어를 기록한다.
	Log.info(itemName);
	
	// Search first, then use the top result's exact name for the detail endpoint.
	const searchUrl = `${config.API_BASE_URL}/api/items?page=0&size=10&sortBy=itemId&sortDir=asc&keyword=${encodeURIComponent(itemName)}`;
	const searchResult = getResponse(searchUrl);
	
	// 검색 결과가 있으면 1순위 아이템명으로 상세 API를 재호출한다.
	if(searchResult && searchResult.content && searchResult.content.length > 0){
		const exactName = searchResult.content[0].itemName;
		const detailUrl = `${config.API_BASE_URL}/api/items/${encodeURIComponent(exactName)}/detail`;
		return getResponse(detailUrl);
	}
	
	// 검색 결과가 없으면 null을 반환한다.
	return null;
}

/**
 * Hole alarm read API.
 * When `holeType` is omitted, the backend returns all alarm rows.
 * @param {string} holeType
 * @returns {object|null}
 */
function getHoleAlarms(holeType){
	// holeType이 있으면 쿼리 파라미터로 필터링한다.
	const holeTypeQuery = holeType ? `?holeType=${encodeURIComponent(holeType)}` : "";
	const url = `${config.API_BASE_URL}/api/hole-alarms${holeTypeQuery}`;
	return requestJson(url, "GET");
}

/**
 * 심구 알림 행을 생성한다.
 * @param {string} regionName
 * @param {string} endTime
 * @param {number} holeCount
 * @returns {object|null}
 */
function createDeepHoleAlarm(regionName, endTime, holeCount){
	const url = `${config.API_BASE_URL}/api/hole-alarms/deep`;
	// 심구 생성 payload를 전달한다.
	return requestJson(url, "POST", {
		regionName,
		endTime,
		holeCount
	});
}

/**
 * 어구 알림 행을 생성한다.
 * @param {string} openTime
 * @returns {object|null}
 */
function createAbyssHoleAlarm(openTime){
	const url = `${config.API_BASE_URL}/api/hole-alarms/abyss`;
	// 오픈 시각만 보내고 나머지는 서버 정책을 따른다.
	return requestJson(url, "POST", {
		openTime
	});
}

/**
 * 처리 완료된 알림을 consume 처리한다.
 * @param {number} alarmId
 * @returns {object|null}
 */
function consumeHoleAlarm(alarmId){
	const url = `${config.API_BASE_URL}/api/hole-alarms/${alarmId}/consume`;
	return requestJson(url, "POST");
}

/**
 * 특정 지역의 심구 알림을 삭제한다.
 * @param {string} regionName
 * @returns {object|null}
 */
function deleteDeepHoleAlarmsByRegion(regionName){
	const url = `${config.API_BASE_URL}/api/hole-alarms/deep?regionName=${encodeURIComponent(regionName)}`;
	return requestJson(url, "DELETE");
}

/**
 * 특정 타입의 알림을 전체 삭제한다.
 * @param {string} holeType
 * @returns {object|null}
 */
function clearHoleAlarms(holeType){
	const url = `${config.API_BASE_URL}/api/hole-alarms/type/${encodeURIComponent(holeType)}`;
	return requestJson(url, "DELETE");
}

/**
 * ABYSS 타입 알림만 삭제하는 헬퍼.
 * @returns {object|null}
 */
function clearAbyssHoleAlarms(){
	return clearHoleAlarms("ABYSS");
}

/**
 * 닉네임 기준 랭킹 정보를 조회한다.
 * @param {string} nickname
 * @returns {object|null}
 */
function getUserRankByNickname(nickname){
	const url = `${config.API_BASE_URL}/api/rank/user?nickname=${encodeURIComponent(nickname)}`;
	return requestJson(url, "GET");
}

/**
 * 게임 공지 목록을 조회한다.
 * @returns {object|null}
 */
function getGameNotices(){
	const url = `${config.API_BASE_URL}/api/notices`;
	return requestJson(url, "GET");
}

/**
 * 게임 이벤트 목록을 조회한다.
 * @returns {object|null}
 */
function getGameEvents(){
	const url = `${config.API_BASE_URL}/api/events`;
	return requestJson(url, "GET");
}

// Public exports used by `mobinogi-bot.js`.

/** @type {Function} */
exports.getMobinogiItem = getMobinogiItem;

/** @type {Function} */
exports.getHoleAlarms = getHoleAlarms;

/** @type {Function} */
exports.createDeepHoleAlarm = createDeepHoleAlarm;

/** @type {Function} */
exports.createAbyssHoleAlarm = createAbyssHoleAlarm;

/** @type {Function} */
exports.consumeHoleAlarm = consumeHoleAlarm;

/** @type {Function} */
exports.deleteDeepHoleAlarmsByRegion = deleteDeepHoleAlarmsByRegion;

/** @type {Function} */
exports.clearHoleAlarms = clearHoleAlarms;

/** @type {Function} */
exports.clearAbyssHoleAlarms = clearAbyssHoleAlarms;

/** @type {Function} */
exports.getUserRankByNickname = getUserRankByNickname;

/** @type {Function} */
exports.getGameNotices = getGameNotices;

/** @type {Function} */
exports.getGameEvents = getGameEvents;
